/**
 * The rand7() API is already defined in the parent class SolBase.
 * public int rand7();
 * @return a random integer in the range1 to7
 */
class Solution extends SolBase {
    public int rand10() {
        int result;
        do {
            int row = rand7();
            int col = rand7();
            result = (row - 1) * 7 + col;
        } while (result > 10);
        return result % 10 + 1;
    }
}
